// ============================================================
// SETTINGS — LOCATION values are static; time window is read from Config
// ============================================================
const LOCATION = 'India';           // Search location
const GEO_ID = '102713980';         // India geoId
const LOCATION_FILTER = '105214831'; // Bengaluru, Karnataka f_PP filter

// Read max opening age (in seconds) from the Config tab; default 21600 (6h).
// Supports a header column named maxAgeSeconds, or a vertical label|value row.
function readCfg(name) {
  try {
    const rows = $('Get Config').all().map(i => i.json);
    for (const r of rows) {
      if (r[name] !== undefined && r[name] !== '') return r[name];
      const vals = Object.values(r);
      if (vals.length >= 2 && String(vals[0]).trim().toLowerCase() === name.toLowerCase()) {
        return vals[1];
      }
    }
  } catch (e) {}
  return undefined;
}
let TIME_WINDOW_SECONDS = Number(readCfg('maxAgeSeconds'));
if (!Number.isFinite(TIME_WINDOW_SECONDS) || TIME_WINDOW_SECONDS <= 0) TIME_WINDOW_SECONDS = 21600;  // default 6h
console.log('Time window (f_TPR): ' + TIME_WINDOW_SECONDS + 's');
// ============================================================

const config =  $input.all().map(i => i.json) || [];
// Define keyword templates per bucket
const bucketKeywords = {
  '1': '"software development engineer" OR "SDE" OR "SDE II" OR "SDE 2" OR "SDE-II" OR "software engineer II" OR "Software Engineer-2" OR "software engineer 2" OR "software engineer - II"',
  '2': '"software engineer III" OR "software engineer 3" OR "software developer 3"',
  '3': '"software engineer" OR "software developer" OR "backend engineer" OR "SDE" OR "MTS" OR "member of technical staff"',
  '4': '"software engineer" OR "software developer" OR "backend engineer" OR "SDE" OR "MTS" OR "member of technical staff"'
};

// Group active companies by bucket
const buckets = {};
for (const item of config) {
  const isActive = String(item.Active).toUpperCase() === 'TRUE' || item.Active === true;
  if (!isActive) continue;

  const bucket = String(item.Bucket);
  if (!buckets[bucket]) buckets[bucket] = [];
  buckets[bucket].push(String(item.CompanyID));
}

// Build LinkedIn search URLs
const urls = [];
for (const [bucket, companyIds] of Object.entries(buckets)) {
  const keywords = bucketKeywords[bucket];
    console.log("bucket: " + bucket);

  if (!keywords || companyIds.length === 0) continue;

  const encodedKeywords = encodeURIComponent(keywords);
  const companyFilter = companyIds.join(',');
  const encodedLocation = encodeURIComponent(LOCATION);

  const url = `https://www.linkedin.com/jobs/search/?keywords=${encodedKeywords}&f_C=${companyFilter}&f_TPR=r${TIME_WINDOW_SECONDS}&location=${encodedLocation}&geoId=${GEO_ID}&f_PP=${LOCATION_FILTER}&sortBy=DD`;


  urls.push({
    url: url,
    bucket: bucket,
    companyCount: companyIds.length
  });
}

console.log(`Built ${urls.length} search URLs for ${Object.keys(buckets).length} active buckets`);

if (urls.length === 0) {
  return [{json: {url: '', bucket: '0', companyCount: 0, noUrls: true}}];
}

return urls.map(u => ({json: u}));

// Reset accumulator at the start of each execution
const staticData = $getWorkflowStaticData('global');
staticData.newJobs = [];
staticData.scoredJobs = [];
return $input.all();

// Store new job data for batch AI scoring later — with EXPERIENCE (years) gating only
const staticData = $getWorkflowStaticData('global');
if (!staticData.newJobs) staticData.newJobs = [];

const jobData = $('Modify Job Attributes').item.json;
const title = String(jobData.title || '');
const description = String(jobData.description || '');

// ── Read experience band [minExp, maxExp] from the Config tab ──
// Supports either a header column named minExp/maxExp, or a vertical
// label|value layout (label in col A, number in col B) like Config!B2..B4.
function readCfg(name) {
  try {
    const rows = $('Get Config').all().map(i => i.json);
    for (const r of rows) {
      if (r[name] !== undefined && r[name] !== '') return r[name];
      const vals = Object.values(r);
      if (vals.length >= 2 && String(vals[0]).trim().toLowerCase() === name.toLowerCase()) {
        return vals[1];
      }
    }
  } catch (e) {}
  return undefined;
}
let minExp = Number(readCfg('minExp'));
let maxExp = Number(readCfg('maxExp'));
if (!Number.isFinite(minExp)) minExp = 0;
if (!Number.isFinite(maxExp)) maxExp = Infinity;

// ── EXPERIENCE FILTER: parse the REQUIRED years, keep only if it overlaps my band ──
// Only matches genuine experience requirements ("<n> years ... experience" or
// "experience: <n> years"), so unrelated prose like "over the past 10 years"
// or "5 years ago" is ignored. A single number is treated as a MINIMUM.
function parseExp(text) {
  const t = text.toLowerCase().replace(/\s+/g, ' ');
  // "<...> experience" tail: years [' ] [of] [relevant/professional/...] experience
  const EXP = "(?:years?|yrs?)(?:['\u2019]s?)?(?:\\s+of)?(?:\\s+(?:relevant|professional|industry|overall|total|work|hands[-\\s]?on|prior|min(?:imum)?|software|engineering))*\\s+experience";
  // range before the experience tail: "3-5 years of experience"
  let m = t.match(new RegExp("(\\d{1,2})\\s*(?:-|\u2013|\u2014|to)\\s*(\\d{1,2})\\s*\\+?\\s*" + EXP));
  if (m) return [Number(m[1]), Number(m[2])];
  // single before the experience tail: "5+ years of experience", "minimum 5 years experience"
  m = t.match(new RegExp("(?:minimum|min|at\\s*least|atleast|over|more than)?\\s*(\\d{1,2})\\s*\\+?\\s*" + EXP));
  if (m) return [Number(m[1]), Infinity];
  // "experience: 3-5 years" / "experience of 5+ years"
  m = t.match(/experience\s*(?:of|:|-)?\s*(\d{1,2})\s*(?:-|\u2013|\u2014|to)\s*(\d{1,2})\s*\+?\s*(?:years?|yrs?)/);
  if (m) return [Number(m[1]), Number(m[2])];
  m = t.match(/experience\s*(?:of|:|-)?\s*(\d{1,2})\s*\+?\s*(?:years?|yrs?)/);
  if (m) return [Number(m[1]), Infinity];
  return null;
}

const jobExp = parseExp(description);
if (jobExp) {
  const [jobMin, jobMax] = jobExp;
  const overlaps = jobMin <= maxExp && jobMax >= minExp; // interval overlap
  if (!overlaps) {
    console.log('[exp-filter] dropped ' + jobMin + '-' + jobMax + ' vs band ' + minExp + '-' + maxExp + ': ' + title);
    return $input.all();
  }
}
// If no experience is stated in the description, the job is kept (per requirement).

staticData.newJobs.push({
  title: jobData.title || '',
  company: jobData.company || '',
  location: jobData.location || '',
  description: jobData.description || '',
  jobid: jobData.jobid || '',
  applyLink: (jobData.applyLink || '').trim()
});

return $input.all();

// BUILD BATCH PROMPT
const staticData = $getWorkflowStaticData('global');
const jobs = staticData.newJobs || [];

if (jobs.length === 0) {
  return [{ json: { hasJobs: false } }];
}

const resume = $('Extract from File').first().json.text || '';
const MAX_DESC = 1500;

const jobSections = jobs.map(job => {
  const desc = (job.description || '').substring(0, MAX_DESC);
  return `---JOB [id: ${job.jobid}]---\nTitle: ${job.title}\nCompany: ${job.company}\nLocation: ${job.location}\nDescription:\n${desc}\n---END JOB---`;
}).join('\n\n');

const prompt = `You are a world-class technical recruiting analyst with deep expertise in software engineering hiring. Your task is to produce rigorous, calibrated match scores between a candidate's resume and multiple job descriptions in a single pass.

## SCORING PHILOSOPHY
- Be brutally honest. A score of 50 means "coin flip".
- Reserve 85+ for near-perfect matches.
- A score below 40 means significant gaps exist.
- Score each job INDEPENDENTLY.

## CANDIDATE RESUME
${resume}

## JOB POSTINGS TO EVALUATE (${jobs.length} job${jobs.length > 1 ? 's' : ''})
Score EACH of the following job postings against the resume above.

${jobSections}

## RESPONSE FORMAT
Respond with ONLY a valid JSON array — no markdown fences, no preamble, no trailing text. I just want the jobid and the score, NOTHING ELSE.

[\n  {"jobid": "<exact id from above>", "score": <total 0-100>},\n  ...\n]\n\nIMPORTANT: You MUST return an entry for EVERY job listed above. Do not skip any.`;

return [{ json: { hasJobs: true, aiPrompt: prompt } }];

// PARSE ALL SCORES
const staticData = $getWorkflowStaticData('global');
const jobs = staticData.newJobs || [];

// Parse AI response
let scores = {};
try {
  const aiText = typeof $json.text === 'string' ? $json.text : (typeof $json.content === 'string' ? $json.content : '');

  const cleaned = aiText
    .replace(/```json\n?/g, '')
    .replace(/```/g, '')
    .trim();

  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) {
    parsed.forEach(s => {
      scores[String(s.jobid)] = s;
    });
  }
} catch (err) {
  // If parsing fails, all jobs get score null
}

// Merge scores with job data — output one item per job
const scoredJobs = jobs.map(job => {
  const s = scores[String(job.jobid)] || {};
  return {
    json: {
      title: job.title,
      company: job.company,
      location: job.location,
      description: job.description,
      jobid: job.jobid,
      applyLink: job.applyLink,
      score: s.score != null ? s.score : null,
      scoreSummary: ""
    }
  };
});

// Store for telegram formatting later
staticData.scoredJobs = scoredJobs.map(j => ({ ...j.json }));

return scoredJobs;

const staticData = $getWorkflowStaticData('global');
const jobs = staticData.scoredJobs || [];

const now = new Date();
const dateStr = now.toLocaleDateString('en-IN', {
  month: 'short', day: 'numeric',
  hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Kolkata'
});

jobs.sort((a, b) => {
  const scoreA = a.score != null ? a.score : -1;
  const scoreB = b.score != null ? b.score : -1;
  return scoreB - scoreA;
});

let header = `\u{1F3AF} *LinkedIn Job Scan*\n`;
header += `\u{1F4C5} ${dateStr} | *${jobs.length}* New Job${jobs.length > 1 ? 's' : ''}\n`;
header += `\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\n\n`;

const jobBlocks = jobs.map((job, i) => {
  let block = `\u{1F4BC} *${job.title}*\n`;
  block += `\u{1F3E2} ${job.company}  \u{1F4CD} ${job.location}\n`;
  if (job.score != null) {
      function scoreEmoji(s) {
          if (s >= 80) return '\u{1F525}';
          if (s >= 65) return '\u{2B50}';
          if (s >= 50) return '\u{1F7E1}';
          if (s >= 35) return '\u{1F7E0}';
          return '\u{26AA}';
      }
      block += `\u{1F916} Match Score: *${job.score}/100* ${scoreEmoji(job.score)}\n`;
  } else {
      block += `\u{1F916} Match Score: _[AI Unavailable]_\n`;
  }
  block += `\u{1F517} [Apply on LinkedIn](${job.applyLink})\n\n`;
  return block;
});

const MAX_LEN = 3800;
const messages = [];
let currentMsg = header;

for (const block of jobBlocks) {
  if ((currentMsg + block).length > MAX_LEN) {
    messages.push(currentMsg);
    currentMsg = `\u{1F3AF} *...continued (${messages.length + 1})*\n\n` + block;
  } else {
    currentMsg += block;
  }
}

currentMsg += `\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\n`;
currentMsg += `\u{23F0} _Next scan in ~6 hours_`;
messages.push(currentMsg);

staticData.newJobs = [];
staticData.scoredJobs = [];

return messages.map(msg => ({ json: { message: msg } }));

// No new jobs found — send a short status message
const now = new Date();
const dateStr = now.toLocaleDateString('en-IN', {
  weekday: 'short', year: 'numeric', month: 'short', day: 'numeric',
  hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Kolkata'
});

const msg = `\u{1F50D} *LinkedIn Job Scan Complete*\n\u{1F4C5} ${dateStr}\n\n\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\n\nNo new jobs found this cycle.\nAll scraped jobs already exist in your sheet.\n\n\u{23F0} _Next scan in ~6 hours_`;

return [{ json: { message: msg } }];
